async (params, browser) => {
  // Open Discord channel
  await browser.open(`${params.channel_url}`)

  // Wait for messages
  await browser.waitForSelector('ol[data-list-id=\'chat-messages\']', 15000)

  await browser.wait(2000)

  // Delete own messages via context menu
  const result = await browser.evaluate(`const maxDelete = Math.min(parseInt('' + params.count + '') || 3, 10); let deleted = 0; const chatList = document.querySelector('ol[data-list-id="chat-messages"]'); if (!chatList) return { success: false, deleted_count: 0, message: 'Chat list not found' }; const msgEls = Array.from(chatList.querySelectorAll('li[id^="chat-messages-"]')).reverse(); for (const el of msgEls) { if (deleted >= maxDelete) break; const hoverBtns = el.querySelector('div[role="toolbar"], div[aria-label="Message Actions"]'); if (!hoverBtns) { el.dispatchEvent(new MouseEvent('mouseenter', { bubbles: true })); await new Promise(r => setTimeout(r, 500)); } const moreBtn = el.querySelector('button[aria-label="More"], button[aria-label*="more"]') || el.querySelector('div[role="toolbar"] button:last-child'); if (!moreBtn) continue; moreBtn.click(); await new Promise(r => setTimeout(r, 500)); const menuItems = document.querySelectorAll('[role="menuitem"], [id*="message-actions"] [role="button"]'); let deleteBtn = null; for (const item of menuItems) { const text = item.textContent.trim().toLowerCase(); if (text.includes('delete') && !text.includes('thread')) { deleteBtn = item; break; } } if (!deleteBtn) { document.dispatchEvent(new KeyboardEvent('keydown', { key: 'Escape', bubbles: true })); continue; } deleteBtn.click(); await new Promise(r => setTimeout(r, 500)); const confirmBtn = document.querySelector('button[type="submit"], div[role="dialog"] button:last-child'); const allBtns = document.querySelectorAll('div[role="dialog"] button'); for (const btn of allBtns) { const text = btn.textContent.trim().toLowerCase(); if (text.includes('delete') || text.includes('confirm')) { btn.click(); deleted++; break; } } await new Promise(r => setTimeout(r, 1500)); } return { success: true, deleted_count: deleted, message: 'Deleted ' + deleted + ' messages' }`)

  return result
}
